namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
                Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
                Steps = ["Toast bread slices.", "Dice tomatoes and mix with garlic and basil.", "Top bread with tomato mixture and drizzle with olive oil."]
            },
            new Recipe
            {
                Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
                Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Parsley", "Breadcrumbs"],
                Steps = ["Remove mushroom stems.", "Mix cream cheese, garlic, and parsley.", "Fill caps and top with breadcrumbs.", "Bake at 375°F for 20 minutes."]
            },
            new Recipe
            {
                Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan cheese", "Black pepper"],
                Steps = ["Cook pasta al dente.", "Fry pancetta until crisp.", "Whisk eggs with parmesan.", "Toss hot pasta with pancetta, then stir in egg mixture off heat."]
            },
            new Recipe
            {
                Id = 4, Title = "Chicken Stir Fry", Category = "Main Courses", CategorySlug = "main-courses",
                Ingredients = ["Chicken breast", "Bell peppers", "Soy sauce", "Ginger", "Rice"],
                Steps = ["Slice chicken and vegetables.", "Stir fry chicken until cooked.", "Add vegetables and soy sauce.", "Serve over steamed rice."]
            },
            new Recipe
            {
                Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
                Steps = ["Melt chocolate and butter together.", "Whisk eggs and sugar, fold in chocolate mixture.", "Add flour gently.", "Bake at 425°F for 12 minutes."]
            },
            new Recipe
            {
                Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
                Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Cocoa powder", "Eggs"],
                Steps = ["Dip ladyfingers in espresso.", "Whisk mascarpone with egg yolks and sugar.", "Layer ladyfingers and cream.", "Dust with cocoa and refrigerate 4 hours."]
            }
        ];
    }

    public List<Recipe> GetByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.CategorySlug).Distinct().ToList();
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];

        _ratings[recipeId].Add(stars);

        var recipe = GetById(recipeId);
        if (recipe != null)
        {
            recipe.RatingCount = _ratings[recipeId].Count;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}

@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes</PageTitle>

@if (string.IsNullOrEmpty(CategorySlug))
{
    <h1>All Categories</h1>
    <ul class="list-group">
        <li class="list-group-item"><a href="recipes/appetizers">🥗 Appetizers</a></li>
        <li class="list-group-item"><a href="recipes/main-courses">🍝 Main Courses</a></li>
        <li class="list-group-item"><a href="recipes/desserts">🍰 Desserts</a></li>
    </ul>
}
else
{
    <h1>@CategorySlug?.Replace("-", " ").ToUpperInvariant()</h1>
    <a href="recipes" class="btn btn-sm btn-outline-secondary mb-3">← All Categories</a>

    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Ingredients.Count ingredients · @recipe.Steps.Count steps</p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(CategorySlug))
        {
            recipes = RecipeService.GetByCategory(CategorySlug);
        }
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <a href="recipes/@recipe.CategorySlug" class="btn btn-sm btn-outline-secondary mb-3">← Back to @recipe.Category</a>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <hr />
    <h4>Rate this Recipe</h4>
    <StarRating RecipeId="recipe.Id" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              style="cursor:pointer; font-size:1.5rem; color: @(star <= selectedRating ? "gold" : "#ccc");">
            ★
        </span>
    }
    @if (selectedRating > 0)
    {
        <span class="ms-2 text-muted">You rated @selectedRating/5</span>
    }
    @if (recipe is not null && recipe.RatingCount > 0)
    {
        <span class="ms-2 text-muted">(Avg: @recipe.AverageRating.ToString("F1") from @recipe.RatingCount ratings)</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedRating;
    private Models.Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(RecipeId);
    }

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        recipe = RecipeService.GetById(RecipeId);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "@title" has been submitted.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText class="form-control" @bind-Value="title" placeholder="Recipe title" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect class="form-select" @bind-Value="category">
                <option value="">-- Select --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="ingredients" rows="5" placeholder="One ingredient per line" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="steps" rows="5" placeholder="One step per line" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>
}

@code {
    private string title = string.Empty;
    private string category = string.Empty;
    private string ingredients = string.Empty;
    private string steps = string.Empty;
    private bool submitted;

    private bool IsValid => !string.IsNullOrWhiteSpace(title)
                         && !string.IsNullOrWhiteSpace(category)
                         && !string.IsNullOrWhiteSpace(ingredients)
                         && !string.IsNullOrWhiteSpace(steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var categoryName = category switch
        {
            "appetizers" => "Appetizers",
            "main-courses" => "Main Courses",
            "desserts" => "Desserts",
            _ => category
        };

        var recipe = new Recipe
        {
            Title = title,
            Category = categoryName,
            CategorySlug = category,
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        submitted = true;
    }

    private void Reset()
    {
        title = string.Empty;
        category = string.Empty;
        ingredients = string.Empty;
        steps = string.Empty;
        submitted = false;
    }
}

