        <li class="list-group-item"><a href="recipes/main-courses">🍝 Main Courses</a></li>
        <li class="list-group-item"><a href="recipes/desserts">🍰 Desserts</a></li>
    </ul>
}
else
{
    <h1>@CategorySlug?.Replace("-", " ").ToUpperInvariant()</h1>
    <a href="recipes" class="btn btn-sm btn-outline-secondary mb-3">← All Categories</a>

    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Ingredients.Count ingredients · @recipe.Steps.Count steps</p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(CategorySlug))
        {
            recipes = RecipeService.GetByCategory(CategorySlug);
        }
    }
}

