toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "@title" has been submitted.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText class="form-control" @bind-Value="title" placeholder="Recipe title" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect class="form-select" @bind-Value="category">
                <option value="">-- Select --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="ingredients" rows="5" placeholder="One ingredient per line" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="steps" rows="5" placeholder="One step per line" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>
}

@code {
    private string title = string.Empty;
    private string category = string.Empty;
    private string ingredients = string.Empty;
    private string steps = string.Empty;
    private bool submitted;

    private bool IsValid => !string.IsNullOrWhiteSpace(title)
                         && !string.IsNullOrWhiteSpace(category)
                         && !string.IsNullOrWhiteSpace(ingredients)
                         && !string.IsNullOrWhiteSpace(steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var categoryName = category switch
        {
            "appetizers" => "Appetizers",
            "main-courses" => "Main Courses",
            "desserts" => "Desserts",
            _ => category
        };

        var recipe = new Recipe
        {
            Title = title,
            Category = categoryName,
            CategorySlug = category,
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        submitted = true;
    }

    private void Reset()
    {
        title = string.Empty;
        category = string.Empty;
        ingredients = string.Empty;
        steps = string.Empty;
        submitted = false;
    }
}

